import styled from "styled-components"

import Brand from "./Brand";
import Introduction from "./Introduction"

import github from '../../img/LandingPage/github.svg'
import mail from '../../img/LandingPage/mail.svg'

const LandingPage = () => {

  return (
    <Container>
      <Nav>
        <Brand />
      </Nav>
      <Introduction />
      <More> More </More>

      <QuickContact>
        <Line />
        <li>
          <a href="https://github.com/energywraith" rel="noopener noreferrer">
            <img src={github} alt="github logo" />
          </a>
        </li>
        <li>
          <a href="a">
            <img src={mail} alt="mail icon" />
          </a>
        </li>
        <Line />
      </QuickContact>
    </Container>
  )
}

const Line = styled.div`
  border-left: 1px solid rgba(255, 255, 255, 0.5);
  height: 10em;
`

const Nav = styled.nav`
  grid-column: 1/3;
`

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: auto 1fr auto / auto auto;
  align-items: center;
  justify-content: space-between;

  font-family: Rubik;
`

const More = styled.span`
  padding: 2em;
`

const QuickContact = styled.ul`
  padding: 0em 1em 6em 0em;
  grid-column: 2;
  grid-row: 2/4;
  display: flex;
  flex-direction: column;
  align-items: center;

  & li a {
    display: inline-block;
    padding: 1em;
    width: 2em;
    height: 2em;
  }

  & img {
    filter: invert(1);
    width: 100%;
    height: 100%;
  }
`

export default LandingPage
